import{c as a,Q as e,j as i,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Text search with CLAP","description":"","frontmatter":{},"headers":[],"relativePath":"user-guide/text-search.md","filePath":"user-guide/text-search.md","lastUpdated":null}'),n={name:"user-guide/text-search.md"};function h(r,s,l,p,o,d){return e(),i("div",null,[...s[0]||(s[0]=[t('<h1 id="text-search-with-clap" tabindex="-1">Text search with CLAP <a class="header-anchor" href="#text-search-with-clap" aria-label="Permalink to &quot;Text search with CLAP&quot;">​</a></h1><p>Audience: UI and CLI users<br> Goal: search by describing sound in words<br> Type: how-to</p><p>CLAP text search compares a written prompt with stored CLAP audio embeddings. It is useful for rough sonic direction: scene, drums, bass, texture, instruments, space, and vocal presence.</p><h2 id="requirement" tabindex="-1">Requirement <a class="header-anchor" href="#requirement" aria-label="Permalink to &quot;Requirement&quot;">​</a></h2><p>Run CLAP audio analysis first:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim analyze </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">models clap </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span></code></pre></div><h2 id="write-a-prompt" tabindex="-1">Write a prompt <a class="header-anchor" href="#write-a-prompt" aria-label="Permalink to &quot;Write a prompt&quot;">​</a></h2><p>Prefer concrete audio language:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>dark hypnotic techno, rolling bass, dry percussion, no vocals</span></span></code></pre></div><p>Avoid relying only on abstract mood words. CLAP does not know your DJ context; it ranks by model similarity.</p><h2 id="search-from-the-ui" tabindex="-1">Search from the UI <a class="header-anchor" href="#search-from-the-ui" aria-label="Permalink to &quot;Search from the UI&quot;">​</a></h2><p>Open the <code>CLAP</code> tab, choose or type a prompt, optionally add a negative prompt, then run <code>CLAP search</code>.</p><h2 id="search-from-cli" tabindex="-1">Search from CLI <a class="header-anchor" href="#search-from-cli" aria-label="Permalink to &quot;Search from CLI&quot;">​</a></h2><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">dj</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">sim text</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">search </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;dark hypnotic techno, rolling bass, no vocals&quot;</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> `</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">limit </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">25</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> `</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">  --</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite</span></span></code></pre></div><p>Expected result:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>&lt;score&gt;    &lt;track_id&gt;    &lt;path&gt;</span></span></code></pre></div><p>Review matches manually before adding them to a set.</p>',17)])])}const u=a(n,[["render",h]]);export{k as __pageData,u as default};
